<svg viewBox="0 0 700 340" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">How Choice Blindness Plays Out in Four Steps</text>
  <text x="20" y="48" fill="#a1a1aa" font-size="13" font-family="sans-serif">Three experiments, three domains — the same pattern</text>
